Rule.Source:
    import sailpoint.object.Link;
    import sailpoint.object.Custom;
    import sailpoint.object.Custom;
    import sailpoint.object.Identity;
    import sailpoint.tools.Util;
    import java.util.Map;
    import java.util.HashMap;
    import sailpoint.object.Attributes;
    import java.text.ParseException;
    import java.text.SimpleDateFormat;
    import java.text.DateFormat;
    import java.util.Date;
    import org.apache.log4j.Logger;
    import org.apache.log4j.Level;
    import java.io.StringWriter;
    import java.io.PrintWriter;

    Logger logger = Logger.getLogger("sailpoint.ascension.rules.gsuite.cube.attribute.orgunitpath");

    boolean isDisabled = false;
    boolean isPastsla=false;
    String customObjectName = "Ascension-Custom-Gsuite";
                             
    String GSuiteStatus = ""; 
    String EA40 = "gsuiteStatus";
	String EA41 = "gsuiteOverrideOU";
    String EA20 = "gsuiteMdm";
    String emplType = "employeeType";

    String EA20Value = "";
    String emplTypeValue = "";
    String defaultOU = "/";
    String gSuiteOU = "";
    String termdate = "99991231";
    String legalHold = "false";
    String ADApplicationName = "";
	String tmpStrEA41=null;
    
    Map gsuite_status_mapping = null;
    List gsuite_excluded_ea40 = new ArrayList();
  
    if(void !=identity && null!=identity && void !=identity.getAttribute(EA40) && null !=identity.getAttribute(EA40)){
        String tmpStr=identity.getAttribute(EA40);
		 tmpStrEA41=identity.getAttribute(EA41);
        if(void !=tmpStr && null!=tmpStr){
            GSuiteStatus=tmpStr.toString();
        }
    
        try{
            if(identity.getAttribute("termDate")!=null){
                termdate = identity.getAttribute("termDate");
            }
        }catch(Exception e){}

        try{
            //ASC_LEGAL_HOLD:TRUE
            if(identity.getAttribute("legalHold")!=null){
                legalHold = identity.getAttribute("legalHold");
            }
        }catch(Exception e){}   
        Custom customObject = context.getObject(Custom.class, customObjectName);
    
        if(void !=customObject && customObject != null ){
            Attributes attrs = customObject.getAttributes();
            if(void !=attrs &&  attrs != null){
                gsuite_status_mapping = attrs.get("gsuite_status_mapping");
                if( void !=gsuite_status_mapping && gsuite_status_mapping != null ){
                    gSuiteOU=GSuiteStatus;
                    if(void !=identity.getAttribute(EA20) && identity.getAttribute(EA20) != null){
                    EA20Value = identity.getAttribute(EA20);
                    }
                    if(void !=identity.getAttribute(emplType) && identity.getAttribute(emplType) != null){
                    emplTypeValue = identity.getAttribute(emplType);
                    }   
                    gSuiteOU = gSuiteOU+"#"+EA20Value+"#"+emplTypeValue;
                }else{
        logger.debug("  gsuite_status_mapping is NULL === ["+gsuite_status_mapping+"]");
      }
              if (attrs.get("gsuite_excluded_ea40") != null) {
								gsuite_excluded_ea40 = attrs.get("gsuite_excluded_ea40");
              }
      }else{
        logger.debug("  attrs is NULL === ["+attrs+"]");
      }
        }else{
        logger.debug("  customObject is NULL === ["+customObject+"]");
      }
    
    
    logger.debug("  gSuiteOU ===>> ["+gSuiteOU+"]");
    String gsuiteString = (String) gsuite_status_mapping.get(gSuiteOU);
    logger.debug("  gsuiteString ===>> ["+gsuiteString+"]");
	
	if(GSuiteStatus!=null &amp;&amp; (GSuiteStatus.equalsIgnoreCase("google_custom"))){
      if( void !=tmpStrEA41 &amp;&amp; null !=tmpStrEA41 ){

        defaultOU=tmpStrEA41;
        identity.setAttribute("orgUnitPath",defaultOU);
      }
      if(void ==tmpStrEA41 &amp;&amp; null==tmpStrEA41 ){
        identity.setAttribute("orgUnitPath",defaultOU);
      }
     
    }
    if(void !=gsuiteString && gsuiteString != null && !gsuiteString.isEmpty() && gsuiteString.contains("#")){
        String[] splitString = gsuiteString.split("#");
        if(splitString.length >0){
            defaultOU=splitString[0];
        }
    } 


    logger.debug("GSuite Status :::"+GSuiteStatus);
    logger.debug("GSuite OU Map :::"+gSuiteOU);
    logger.debug("Default OrgUnit Path :::"+defaultOU);
    logger.debug("Legal Hold :::"+legalHold);
    logger.debug("Termination date :::"+termdate);
    
    
    List identityLinks = identity.getLinks();
        for (int i = 0; i < identityLinks.size(); i++) {
            Link account = identityLinks.get(i);
            String ApplicationName = account.getApplicationName(); 
            logger.debug("Application :::"+ApplicationName);
            isDisabled = false;

            if(ApplicationName.contains("AD-")){
                ADApplicationName=ApplicationName;
                isDisabled = account.isDisabled();
                break;
            }
        }
    
    logger.debug("ADMIN OrgUnitPath Validation ==== Inprogress");
        if(GSuiteStatus.contains("ADMIN") && (isDisabled) && (!GSuiteStatus.equalsIgnoreCase("ADMIN_inactive"))){
       identity.setAttribute("orgUnitPath","/Inactive");
        }else if (Util.containsComparable(gsuite_excluded_ea40, GSuiteStatus.toLowerCase(), false)) {
						return;
        }else if (  (GSuiteStatus.contains("EMP") || GSuiteStatus.contains("CWR") ) && isDisabled &&  !termdate.equals("99991231") && ( legalHold.equalsIgnoreCase("true") || legalHold.equalsIgnoreCase("-1") )) {
            logger.debug("EMP or CWR OrgUnitPath Validation ==== Inprogress");
            int termSLA = 90;
            try{
                String termSLAObj = "Ascension-Custom-TerminationApplication";
                Custom customtermSLAObj = context.getObject(Custom.class, termSLAObj);
                if(customtermSLAObj != null ){
                    termSLA = customtermSLAObj.getInt("termSLA");
                    logger.debug("Termination SLA ==== "+termSLA);
                }
            }catch(Exception e){
            }
            
            try {
                Date termDateObject = new SimpleDateFormat("yyyyMMdd").parse(termdate);
                Date currentDate = new Date();
                long dateDiff = currentDate.getTime() - termDateObject.getTime();
                long diffDays = dateDiff / (24 * 60 * 60 * 1000);
                
                logger.debug("diffDays ==== "+diffDays);
                logger.debug("Term Date SLA ==== "+termSLA);

                if (diffDays >= termSLA) {
          identity.setAttribute("orgUnitPath","/Inactive");
                }
            } catch (ParseException e) {
        identity.setAttribute("orgUnitPath",defaultOU);
            }
        }else{
      identity.setAttribute("orgUnitPath",defaultOU);
        }

}else{
 
return;

}
